# Stage 1: skeleton via partial correlation tests
for (i, j) in all_pairs:
    for sep_set in subsets(V - {i,j}):
        if partial_corr_pval(i, j, sep_set) > 0.05:
            skeleton.remove_edge(i, j)
            break

# Stage 2: orient v-structures
# X -> Z <- Y where X,Y not adjacent
for (X, Z, Y) in unshielded_triples(skeleton):
    if Z not in sep_set[X][Y]:  # Z is a collider
        orient(X -> Z <- Y)
